export const receive = <T>(
  receiver: SourceSignal<T>,
  ...transmittors: MaybeSignal<T>[]
): SignalsEffect[] => {
  const effects = transmittors.map((transmittor) =>
    effect(() => (receiver.value = value(transmittor))),
  );
  return effects;
};

